# --- LECTURA OPTIMIZADA CON CACHE (ANTI-BLOQUEOS 429) ---
@st.cache_data(ttl=3)
def leer_base_datos():
    ops, inv, deu, extra = [], [], [], []
    if sh:
        try:
            ops = sh.worksheet("Operaciones").get_all_values()
        except Exception:
            pass
        try:
            inv = sh.worksheet("Inventario").get_all_records()
        except Exception:
            pass
        try:
            deu = sh.worksheet("Deudas").get_all_records()
        except Exception:
            pass
        try:
            extra = sh.worksheet("Menu_Extra").get_all_records()
        except Exception:
            pass
    return ops, inv, deu, extra

datos_ops_global, datos_inv_global, datos_deudas_global, datos_menu_extra_global = leer_base_datos()

