# --- FUSION DEL MENU BASE + PRODUCTOS AGREGADOS DESDE ADMIN (Menu_Extra) ---
def construir_menu_final():
    menu_final = {cat: dict(productos) for cat, productos in MENU.items()}
    for fila in datos_menu_extra_global:
        cat = fila.get("Categoria") or "\u2795 Extra (Admin)"
        nombre = fila.get("Producto")
        try:
            precio = float(fila.get("Precio", 0))
        except Exception:
            precio = 0.0
        if not nombre:
            continue
        if cat not in menu_final:
            menu_final[cat] = {}
        menu_final[cat][nombre] = precio
    return menu_final

