# --- LISTA DE CLIENTES CONOCIDOS (para el selector con busqueda) ---
def obtener_clientes_conocidos():
    nombres = set()
    for fila in datos_deudas_global:
        c = fila.get("Cliente")
        if c and c not in ("X", "Mostrador"):
            nombres.add(c)
    for fila in datos_ops_global[1:]:
        if fila and fila[0] and fila[0] not in ("X", "Mostrador"):
            nombres.add(fila[0])
    return sorted(nombres)

def selector_cliente(key_base, valor_por_defecto="X"):
    """Selectbox con busqueda (nativa de Streamlit al escribir) + opcion de cliente nuevo."""
    conocidos = obtener_clientes_conocidos()
    opciones = ["X"] + conocidos + ["\u2795 Nuevo cliente..."]
    seleccion = st.selectbox("\U0001F464 Cliente:", opciones, index=0, key=f"{key_base}_sel")
    if seleccion == "\u2795 Nuevo cliente...":
        return st.text_input("Nombre del nuevo cliente:", value="", key=f"{key_base}_nuevo")
    return seleccion

# --- FUNCION MAESTRA DE MONITORES ---
def mostrar_pedidos(destino_filtro, estado_actual, texto_boton, nuevo_estado, ordenar_por_urgencia=False):
    if not sh or len(datos_ops_global) <= 1:
        st.info("Todo tranquilo por aqui. \U0001F60E")
        return

    try:
        ws_ops_local = sh.worksheet("Operaciones")
        filas_a_mostrar = []
        for i, fila in enumerate(datos_ops_global[1:], start=2):
            if len(fila) < 7: continue

            cliente, producto, destino, notas, tiempo, hora, estado = fila[0], fila[1], fila[2], fila[3], fila[4], fila[5], fila[6]
            fecha_fila = fila[8] if len(fila) > 8 else hoy_str

            if fecha_fila != hoy_str: continue

            mostrar = False
            if destino_filtro:
                if destino == destino_filtro and estado == estado_actual: mostrar = True
            else:
                if estado == estado_actual: mostrar = True

            if mostrar:
                filas_a_mostrar.append((i, cliente, producto, notas, tiempo, hora))

        if ordenar_por_urgencia:
            def _clave_orden(item):
                _, _, _, _, tiempo_item, hora_item = item
                prioridad = 0 if tiempo_item == "Ahora" else 1
                try:
                    fecha_hora = datetime.strptime(hora_item, "%d/%m/%Y %H:%M")
                except Exception:
                    fecha_hora = datetime.max
                return (prioridad, fecha_hora)
            filas_a_mostrar.sort(key=_clave_orden)

        mostrados = 0
        for i, cliente, producto, notas, tiempo, hora in filas_a_mostrar:
            mostrados += 1
            with st.container():
                col_info, col_btn = st.columns([3, 2])
                with col_info:
                    st.markdown(f"### \U0001F6D2 {producto}")
                    st.write(f"\U0001F464 **Cliente:** {cliente}")
                    horario_especial = formatear_horario(tiempo, hora)
                    if horario_especial:
                        st.markdown(f"<span style='font-size:20px; font-weight:bold; color:#0073E6;'>\U0001F552 Entregar a las {horario_especial}</span>", unsafe_allow_html=True)
                    else:
                        st.caption("\u26A1 Para AHORA")
                    if notas: st.warning(f"\U0001F4DD **Notas:** {notas}")
                with col_btn:
                    st.write("")
                    if st.button(f"{texto_boton} \u2705", key=f"btn_{i}_{estado_actual}"):
                        ws_ops_local.update_cell(i, 7, nuevo_estado)
                        leer_base_datos.clear()
                        st.rerun()
            st.divider()
        if mostrados == 0: st.info("ERES LIBRE DE SENTARTE.")
    except Exception as e:
        st.error(f"Error al actualizar monitor: {e}")

def contar_pendientes_cocina():
    total = 0
    for fila in datos_ops_global[1:]:
        if len(fila) < 7: continue
        destino, estado = fila[2], fila[6]
        fecha_fila = fila[8] if len(fila) > 8 else hoy_str
        if destino == "Cocina" and estado == "Preparando" and fecha_fila == hoy_str:
            total += 1
    return total

